using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Scores { get; set; } = new();
}

public class EvaluationMetrics
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainingService
{
    private readonly string _dataPath;
    private readonly string _modelPath;
    private readonly ILogger<ModelTrainingService> _logger;

    public EvaluationMetrics? Metrics { get; private set; }

    public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public void TrainAndSave()
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Featurize text columns and combine with Priority
        var pipeline = mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features", "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model from {DataPath}...", _dataPath);
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate on test set
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions, labelColumnName: "Label");

        Metrics = new EvaluationMetrics
        {
            MacroAccuracy = metrics.MacroAccuracy,
            MicroAccuracy = metrics.MicroAccuracy,
            LogLoss = metrics.LogLoss,
            LogLossReduction = metrics.LogLossReduction
        };

        _logger.LogInformation(
            "Model evaluation — MacroAccuracy: {Macro:F4}, MicroAccuracy: {Micro:F4}, LogLoss: {LogLoss:F4}, LogLossReduction: {Reduction:F4}",
            Metrics.MacroAccuracy, Metrics.MicroAccuracy, Metrics.LogLoss, Metrics.LogLossReduction);

        mlContext.Model.Save(model, data.Schema, _modelPath);
        _logger.LogInformation("Model saved to {ModelPath}", _modelPath);
    }

    public string ModelPath => _modelPath;
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _pool;
    private readonly ModelTrainingService _trainingService;

    // Category labels in the order ML.NET encodes them (alphabetical by default for SDCA)
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> pool,
        ModelTrainingService trainingService)
    {
        _pool = pool;
        _trainingService = trainingService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject ?? string.Empty,
            Description = request.Description ?? string.Empty,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < CategoryLabels.Length; i++)
            scores[CategoryLabels[i]] = prediction.Score[i];

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Scores = scores
        });
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        if (_trainingService.Metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(_trainingService.Metrics);
    }
}

