using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _pool;
    private readonly ModelTrainingService _trainingService;

    // Category labels in the order ML.NET encodes them (alphabetical by default for SDCA)
    private static readonly string[] CategoryLabels = ["Billing", "General", "Technical"];

    public TicketsController(
        PredictionEnginePool<TicketInput, TicketPrediction> pool,
        ModelTrainingService trainingService)
    {
        _pool = pool;
        _trainingService = trainingService;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject ?? string.Empty,
            Description = request.Description ?? string.Empty,
            Priority = request.Priority
        };

        var prediction = _pool.Predict(input);

        var scores = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < CategoryLabels.Length; i++)
            scores[CategoryLabels[i]] = prediction.Score[i];

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Scores = scores
        });
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationMetrics> GetMetrics()
    {
        if (_trainingService.Metrics is null)
            return NotFound("Model has not been trained yet.");

        return Ok(_trainingService.Metrics);
    }
}

